import{_ as o,o as a,c as t,ag as d}from"./chunks/framework.eQLvDOR_.js";const C=JSON.parse('{"title":"claude-code-mastery","description":"","frontmatter":{"title":"claude-code-mastery","concept":"Claude Code Mastery","concept_id":"claude-code-mastery","aliases":["Claude-Code-技巧","CLI-Efficiency"],"sources":["02_Library/AI_IDE_And_CLI/[AI_IDE_And_CLI] Claude Code 完全リファレンス — 全機能網羅+意外と知らない便利機能トップ10.md","02_Library/AI_IDE_And_CLI/[AI_IDE_And_CLI] 【入門記事】ClaudeCodeの中級者になりたい人は集合してください.md"],"related_concepts":["[[skill-lifecycle]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/claude-code-mastery.md","filePath":"wiki/concepts/claude-code-mastery.md","lastUpdated":null}'),l={name:"wiki/concepts/claude-code-mastery.md"};function r(c,e,s,i,n,_){return a(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="claude-code-mastery-进阶技巧" tabindex="-1">Claude Code Mastery (进阶技巧) <a class="header-anchor" href="#claude-code-mastery-进阶技巧" aria-label="Permalink to &quot;Claude Code Mastery (进阶技巧)&quot;">​</a></h1><h2 id="提升效率的-top-10-功能" tabindex="-1">提升效率的 Top 10 功能 <a class="header-anchor" href="#提升效率的-top-10-功能" aria-label="Permalink to &quot;提升效率的 Top 10 功能&quot;">​</a></h2><ol><li><strong><code>/btw</code> (Side Question)</strong>：在不污染主对话上下文的情况下提问。它利用 Prompt Cache 降低成本，适合询问术语或轻量概念。</li><li><strong><code>Ctrl+S</code> (Stash)</strong>：暂存当前正在编写的 Prompt，处理紧急任务后再自动恢复。</li><li><strong><code>Ctrl+B</code> (Background)</strong>：将长耗时任务（如运行全量测试）移至后台，主终端继续接收指令。</li><li><strong><code>--bare</code> (轻量模式)</strong>：跳过所有 Hook、LSP 和初始化插件，实现秒级启动，适合 CI/CD 或单次脚本调用。</li><li><strong><code>/loop</code> (循环执行)</strong>：在本地以指定间隔运行命令（如每 5 分钟跑一次测试），最长可运行 3 天。</li><li><strong><code>!Command</code> (Shell 直达)</strong>：在指令前加 <code>!</code> 绕过 LLM 推论直接执行系统命令，节省 Token。</li><li><strong><code>/rewind</code> (撤销)</strong>：一键撤销 Claude 刚才产生的所有文件系统修改。</li><li><strong><code>/compact</code> (上下文压缩)</strong>：当 Token 接近 80% 时，用摘要替换冗长对话记录以释放空间。</li><li><strong><code>worktree.sparsePaths</code></strong>：在大规模 Monorepo 中仅加载相关目录，显著提升启动速度。</li><li><strong><code>Ctrl+G</code> (外部编辑器)</strong>：调用 <code>$EDITOR</code> (如 Vim/VS Code) 编写复杂的结构化 Prompt。</li></ol><h2 id="实战建议" tabindex="-1">实战建议 <a class="header-anchor" href="#实战建议" aria-label="Permalink to &quot;实战建议&quot;">​</a></h2><ul><li><strong>权限管理</strong>：建议使用 <code>acceptEdits</code> 模式允许文件修改自动通过，但保留命令执行确认。</li><li><strong>自动化集成</strong>：结合 <code>-p</code> (非交互模式) 和 <code>--output-format json</code> 构建自动化工作流。</li></ul><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>成本控制</strong>：在长 Session 结尾使用 <code>Ctrl+W</code> 或 <code>/compact</code> 及时重置上下文。</li><li><strong>自动化流</strong>：配置别名 <code>alias c=&quot;claude-code -p \\&quot;$@\\&quot;&quot;</code>，实现命令行级的高效调用。</li><li><strong>插件维护</strong>：定期清理不常用的 MCP 服务器，过多的工具描述会显著拉高每个 Token 的 Prompt 成本。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - Claude Code 完全リファレンス — 全機能網羅%2B意外と知らない便利機能トップ10.html">[AI_IDE_And_CLI] Claude Code 完全リファレンス</a></li><li><a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - 【入門記事】ClaudeCodeの中級者になりたい人は集合してください.html">[AI_IDE_And_CLI] 【入門記事】ClaudeCodeの中級者になりたい人は集合してください</a></li></ul>',11)])])}const p=o(l,[["render",r]]);export{C as __pageData,p as default};
